proof fn lemma_glb_index_unique<K: KeyTrait + VerusClone>(
    s: &StrictlyOrderedMap<K>,
    iter: KeyIterator<K>,
    r1: usize,
    r2: usize,
)
    requires
        s.valid(),
        0 <= r1 < s.keys@.len(),
        0 <= r2 < s.keys@.len(),
        s.greatest_lower_bound_spec(iter, KeyIterator::new_spec(s.keys@[r1 as int])),
        s.greatest_lower_bound_spec(iter, KeyIterator::new_spec(s.keys@[r2 as int])),
    ensures
        r1 == r2,
{
    K::cmp_properties();

    let k1 = s.keys@[r1 as int];
    let k2 = s.keys@[r2 as int];
    let glb1: KeyIterator<K> = KeyIterator::new_spec(k1);
    let glb2: KeyIterator<K> = KeyIterator::new_spec(k2);

    assert(s.keys@.contains(k1));
    assert(s.keys@.contains(k2));
    assert(s@.contains_key(k1));
    assert(s@.contains_key(k2));

    if r1 != r2 {
        if (r1 as int) < (r2 as int) {
            assert(k1.cmp_spec(k2).lt());
            assert(k1 != k2);
            assert(glb1 != glb2);

            if iter.is_end_spec() {
                assert(iter.above(k2));
                assert(KeyIterator::<K>::new_spec(k2) != glb1);
                assert(glb1.above(k2));
                assert(k2.cmp_spec(k1).lt());
                assert(false);
            } else {
                assert(iter.k is Some);
                if glb2 == iter {
                    assert(exists|hi: KeyIterator<K>|
                        s.gap(glb1, hi) && KeyIterator::between(glb1, iter, hi));
                    let hi = choose|hi: KeyIterator<K>|
                        s.gap(glb1, hi) && KeyIterator::between(glb1, iter, hi);
                    assert(s.gap(glb1, hi));
                    assert(KeyIterator::between(glb1, iter, hi));
                    assert(iter.lt_spec(hi));
                    assert(glb1.lt_spec(iter));
                    assert(*iter.get() == k2);
                    assert(glb1.lt_spec(iter) && iter.lt_spec(hi));
                    assert(!s@.contains_key(*iter.get()));
                    assert(!s@.contains_key(k2));
                    assert(false);
                } else {
                    assert(glb2.lt_spec(iter));
                    assert(k2.cmp_spec(iter.k->Some_0).lt());
                    assert(iter.above(k2));
                    assert(KeyIterator::<K>::new_spec(k2) != glb1);
                    assert(glb1.above(k2));
                    assert(k2.cmp_spec(k1).lt());
                    assert(false);
                }
            }
        } else {
            assert((r2 as int) < (r1 as int));
            assert(k2.cmp_spec(k1).lt());
            assert(k1 != k2);
            assert(glb1 != glb2);

            if iter.is_end_spec() {
                assert(iter.above(k1));
                assert(KeyIterator::<K>::new_spec(k1) != glb2);
                assert(glb2.above(k1));
                assert(k1.cmp_spec(k2).lt());
                assert(false);
            } else {
                assert(iter.k is Some);
                if glb1 == iter {
                    assert(exists|hi: KeyIterator<K>|
                        s.gap(glb2, hi) && KeyIterator::between(glb2, iter, hi));
                    let hi = choose|hi: KeyIterator<K>|
                        s.gap(glb2, hi) && KeyIterator::between(glb2, iter, hi);
                    assert(s.gap(glb2, hi));
                    assert(KeyIterator::between(glb2, iter, hi));
                    assert(iter.lt_spec(hi));
                    assert(glb2.lt_spec(iter));
                    assert(*iter.get() == k1);
                    assert(glb2.lt_spec(iter) && iter.lt_spec(hi));
                    assert(!s@.contains_key(*iter.get()));
                    assert(!s@.contains_key(k1));
                    assert(false);
                } else {
                    assert(glb1.lt_spec(iter));
                    assert(k1.cmp_spec(iter.k->Some_0).lt());
                    assert(iter.above(k1));
                    assert(KeyIterator::<K>::new_spec(k1) != glb2);
                    assert(glb2.above(k1));
                    assert(k1.cmp_spec(k2).lt());
                    assert(false);
                }
            }
        }
    }
}
